class FenwickTree:
    def __init__(self, size):
        self.tree = [0] * (size + 1)
        self.size = size

    def update(self, index, val):
        while index <= self.size:
            self.tree[index] += val
            index += index & (-index)

    def query(self, index):
        s = 0
        while index > 0:
            s += self.tree[index]
            index -= index & (-index)
        return s

def count_inversions(arr):
    if not arr:
        return 0

    unique_elements = sorted(list(set(arr)))
    rank_map = {val: i + 1 for i, val in enumerate(unique_elements)}

    compressed_arr = [rank_map[x] for x in arr]

    max_rank = len(unique_elements)

    ft = FenwickTree(max_rank)

    total_inversions = 0

    for i in range(len(compressed_arr) - 1, -1, -1):
        current_rank = compressed_arr[i]

        total_inversions += ft.query(current_rank - 1)

        ft.update(current_rank, 1)

    return total_inversions
